import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { db } from '../firebase';
import { doc, getDoc, collection, getDocs } from 'firebase/firestore';

function TeamLineup() {
  const { teamId } = useParams();
  const navigate = useNavigate();
  const [teamData, setTeamData] = useState(null);
  const [players, setPlayers] = useState([]);
  const [lineup, setLineup] = useState([]);
  const [showPlayerSelection, setShowPlayerSelection] = useState(false);
  const [selectedSlotIndex, setSelectedSlotIndex] = useState(null);
  const [pinVerified, setPinVerified] = useState(false);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const teamRef = doc(db, 'teams', teamId);
        const teamSnap = await getDoc(teamRef);
        if (teamSnap.exists()) {
          setTeamData(teamSnap.data());
          setLineup(Array(teamSnap.data().playerCount).fill(null));
        } else {
          alert('Team not found');
          navigate('/teams-management');
        }

        const playersSnap = await getDocs(collection(db, 'players'));
        const playersData = playersSnap.docs.map(doc => ({
          id: doc.id,
          ...doc.data(),
        }));
        setPlayers(playersData);
      } catch (error) {
        console.error('Error fetching data:', error);
      }
    };

    fetchData();
  }, [teamId, navigate]);

  // Only verify PIN after data is loaded
  useEffect(() => {
    if (teamData) {
      verifyPin();
    }
  }, [teamData]);

  const verifyPin = () => {
    const userPin = prompt("Enter PIN:");
    if (userPin === teamData.pin) {
      setPinVerified(true);
    } else {
      alert("Incorrect PIN.");
      navigate('/teams-management');
    }
  };

  const handleSelectPlayer = (index) => {
    setSelectedSlotIndex(index);
    setShowPlayerSelection(true);
  };

  const assignPlayerToSlot = (player) => {
    const updatedLineup = [...lineup];
    updatedLineup[selectedSlotIndex] = player;
    setLineup(updatedLineup);
    setShowPlayerSelection(false);
  };

  if (!pinVerified) {
    verifyPin();
    return null;
  }

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>{teamData.name} - Lineup</h1>

      <img
        src={`${process.env.PUBLIC_URL}/images/Tactics/${teamData.playerCount}_players_${teamData.tactic}.png`}
        alt="Tactic"
        style={styles.tacticImage}
      />

      <div style={styles.lineupContainer}>
        {lineup.map((player, index) => (
          <div key={index} style={styles.slot} onClick={() => handleSelectPlayer(index)}>
            {player ? (
              <>
                <img
                  src={player.profilePicture || `${process.env.PUBLIC_URL}/images/profile_picture.jpg`}
                  alt="Player"
                  style={styles.playerImage}
                />
                <p style={styles.playerName}>{player.lastName}, {player.firstName}</p>
                <p style={styles.playerPosition}>{player.favoritePosition}</p>
                <p style={styles.playerPower}>Power: {player.powerRating}</p>
              </>
            ) : (
              <p style={styles.emptySlot}>+ Slot {index + 1}</p>
            )}
          </div>
        ))}
      </div>

      {showPlayerSelection && (
        <div style={styles.overlay}>
          <div style={styles.playerSelectionContainer}>
            <h3>Select a Player</h3>
            <div style={styles.playerGrid}>
              {players.map((player) => (
                <div
                  key={player.id}
                  style={styles.playerCard}
                  onClick={() => assignPlayerToSlot(player)}
                >
                  <img
                    src={player.profilePicture || `${process.env.PUBLIC_URL}/images/profile_picture.jpg`}
                    alt="Player"
                    style={styles.playerCardImage}
                  />
                  <p>{player.lastName}, {player.firstName}</p>
                  <p>{player.favoritePosition}</p>
                  <p>Power: {player.powerRating}</p>
                </div>
              ))}
            </div>
            <button style={styles.closeButton} onClick={() => setShowPlayerSelection(false)}>
              Cancel
            </button>
          </div>
        </div>
      )}

      <button style={styles.backButton} onClick={() => navigate('/teams-management')}>
        Back to Teams Management
      </button>
    </div>
  );
}

const styles = {
  container: {
    backgroundColor: '#D6F8D6',
    minHeight: '100vh',
    padding: '20px',
    fontFamily: "'Press Start 2P', cursive",
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  },
  title: {
    fontSize: '24px',
    marginBottom: '20px',
    color: '#293F14',
  },
  tacticImage: {
    width: '50%',
    height: 'auto',
    marginBottom: '30px',
    borderRadius: '10px',
  },
  lineupContainer: {
    display: 'flex',
    justifyContent: 'center',
    gap: '20px',
    flexWrap: 'wrap',
    width: '80%',
  },
  slot: {
    width: '120px',
    height: '160px',
    backgroundColor: '#7FC6A4',
    borderRadius: '10px',
    border: '2px solid #5D737E',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    cursor: 'pointer',
    boxShadow: '3px 3px #386C0B',
  },
  playerImage: {
    width: '60px',
    height: '60px',
    borderRadius: '50%',
    marginBottom: '5px',
  },
  playerName: {
    fontSize: '12px',
    fontWeight: 'bold',
    textAlign: 'center',
  },
  playerPosition: {
    fontSize: '10px',
    color: '#293F14',
  },
  playerPower: {
    fontSize: '10px',
    textDecoration: 'underline',
  },
  emptySlot: {
    fontSize: '14px',
    color: '#293F14',
  },
  overlay: {
    position: 'fixed',
    top: 0,
    left: 0,
    width: '100vw',
    height: '100vh',
    backgroundColor: 'rgba(0,0,0,0.8)',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
  },
  playerSelectionContainer: {
    backgroundColor: '#FFFFFF',
    padding: '20px',
    borderRadius: '10px',
    width: '60%',
  },
  playerGrid: {
    display: 'flex',
    gap: '10px',
    flexWrap: 'wrap',
  },
  playerCard: {
    width: '100px',
    padding: '10px',
    backgroundColor: '#D6F8D6',
    textAlign: 'center',
    borderRadius: '8px',
    cursor: 'pointer',
  },
  playerCardImage: {
    width: '50px',
    height: '50px',
    borderRadius: '50%',
  },
  closeButton: {
    marginTop: '20px',
    padding: '10px',
    backgroundColor: '#FF4D4D',
    color: '#FFF',
  },
  backButton: {
    marginTop: '20px',
    backgroundColor: '#5D737E',
    padding: '10px',
  },
};

export default TeamLineup;
